# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs). Prevent directory traversal attacks.
# Category: path_traversal

using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;

namespace FileServer.Controllers
{
    public class FileController : Controller
    {
        private const string RootDirectory = "Uploads";

        [ResponseCache(Duration = 0, Location = ResponseCacheLocation.None, NoStore = true)]
        public IActionResult Download(string fileName)
        {
            try
            {
                var validExtensions = new[] { ".doc", ".pdf", ".jpg", ".jpeg", ".png" };
                var filePath = Path.Combine(RootDirectory, fileName);

                if (File.Exists(filePath) && validExtensions.Any(ext => fileName.EndsWith(ext, StringComparison.OrdinalIgnoreCase)))
                {
                    var contentType = MimeTypes.GetMimeType(Path.GetExtension(filePath));
                    var fileStream = File.OpenRead(filePath);
                    return File(fileStream, contentType, fileName);
                }
            }
            catch
            {
                // Handle exceptions here if needed
            }

            return NotFound();
        }
    }
}